commands.commands:
@echo off
setlocal EnableExtensions
set "AAOS_BAT_PATH=%~f0"

REM aaos_dump_report.bat
REM Windows BAT wrapper + embedded PowerShell parser.
REM Collects and summarizes:
REM   adb shell dumpsys activity
REM   adb shell dumpsys activity activities
REM   adb shell dumpsys window
REM
REM Usage:
REM   aaos_dump_report.bat
REM   aaos_dump_report.bat -s emulator-5554
REM   aaos_dump_report.bat --raw-dir .\raw_dump
REM   aaos_dump_report.bat --keep-raw
REM   aaos_dump_report.bat --commands .\commands.txt

powershell -NoProfile -ExecutionPolicy Bypass -Command "$ErrorActionPreference='Stop'; $bat=$env:AAOS_BAT_PATH; $src=Get-Content -LiteralPath $bat; $marker=($src | Select-String -Pattern '^# POWERSHELL_START$' | Select-Object -First 1); if(-not $marker){ throw 'PowerShell marker not found in BAT file.' }; $code=($src[$marker.LineNumber..($src.Count-1)] -join [Environment]::NewLine); & ([scriptblock]::Create($code)) @args" %*
set "EXIT_CODE=%ERRORLEVEL%"
endlocal & exit /b %EXIT_CODE%

# POWERSHELL_START
param(
    [Parameter(ValueFromRemainingArguments = $true)]
    [string[]] $CliArgs
)

$ErrorActionPreference = 'Stop'

$ScriptFile = $env:AAOS_BAT_PATH
$ScriptDir = Split-Path -Parent $ScriptFile

$DeviceSerial = ''
$CommandsFile = Join-Path $ScriptDir 'commands.txt'
$RawDir = ''
$KeepRaw = $false
$LimitWindows = 60
$LimitTasks = 80
$LimitServices = 80
$LimitProcesses = 40

function Show-Usage {
@"
Usage:
  aaos_dump_report.bat [options]

Options:
  -s, --serial <device_serial>   Use a specific adb device/emulator, e.g. emulator-5554
  --commands <file>              Commands config file. Default: .\commands.txt
  --raw-dir <dir>                Save raw dumpsys outputs to this directory
  --keep-raw                     Keep raw dumps in a temporary directory and print its path
  -h, --help                     Show help

Examples:
  aaos_dump_report.bat
  aaos_dump_report.bat -s emulator-5554
  aaos_dump_report.bat --raw-dir .\raw_dump
"@
}

for ($i = 0; $i -lt $CliArgs.Count; $i++) {
    switch ($CliArgs[$i]) {
        '-s' { $i++; if ($i -ge $CliArgs.Count) { throw 'Missing value for -s' }; $DeviceSerial = $CliArgs[$i]; continue }
        '--serial' { $i++; if ($i -ge $CliArgs.Count) { throw 'Missing value for --serial' }; $DeviceSerial = $CliArgs[$i]; continue }
        '--commands' { $i++; if ($i -ge $CliArgs.Count) { throw 'Missing value for --commands' }; $CommandsFile = $CliArgs[$i]; continue }
        '--raw-dir' { $i++; if ($i -ge $CliArgs.Count) { throw 'Missing value for --raw-dir' }; $RawDir = $CliArgs[$i]; continue }
        '--keep-raw' { $KeepRaw = $true; continue }
        '-h' { Show-Usage; exit 0 }
        '--help' { Show-Usage; exit 0 }
        default { throw "Unknown option: $($CliArgs[$i])" }
    }
}

function Ensure-DefaultCommandsFile {
    param([string] $Path)

    if (Test-Path -LiteralPath $Path) { return }

    $defaultCommands = @(
        '# key|adb shell command without the adb shell prefix',
        'activity|dumpsys activity',
        'activities|dumpsys activity activities',
        'window|dumpsys window'
    )

    $parent = Split-Path -Parent $Path
    if ($parent -and -not (Test-Path -LiteralPath $parent)) {
        New-Item -ItemType Directory -Path $parent -Force | Out-Null
    }

    $defaultCommands | Set-Content -LiteralPath $Path -Encoding ASCII
    Write-Host "[init] Created default commands file: $Path"
}

function Read-CommandsFile {
    param([string] $Path)

    Ensure-DefaultCommandsFile -Path $Path

    $map = @{}
    foreach ($line in Get-Content -LiteralPath $Path) {
        $trimmed = $line.Trim()
        if ([string]::IsNullOrWhiteSpace($trimmed)) { continue }
        if ($trimmed.StartsWith('#')) { continue }
        $parts = $trimmed.Split('|', 2)
        if ($parts.Count -lt 2) { continue }
        $key = $parts[0].Trim()
        $cmd = $parts[1].Trim()
        if ($key -and $cmd) { $map[$key] = $cmd }
    }

    foreach ($required in @('activity', 'activities', 'window')) {
        if (-not $map.ContainsKey($required)) {
            throw "Missing command key '$required' in $Path"
        }
    }

    return $map
}

function Section {
    param([string] $Title)
    Write-Host ''
    Write-Host '============================================================'
    Write-Host $Title
    Write-Host '============================================================'
}

function First-LineMatch {
    param(
        [string[]] $Lines,
        [string] $Pattern
    )
    foreach ($line in $Lines) {
        if ($line -match $Pattern) { return $line.Trim() }
    }
    return ''
}

function Print-Matches {
    param(
        [string[]] $Lines,
        [string] $Pattern,
        [int] $Limit = 20,
        [string] $Prefix = '  - ',
        [switch] $Unique
    )

    $seen = @{}
    $count = 0
    foreach ($line in $Lines) {
        if ($line -notmatch $Pattern) { continue }
        $text = ($line -replace '\s+', ' ').Trim()
        if ($Unique) {
            if ($seen.ContainsKey($text)) { continue }
            $seen[$text] = $true
        }
        Write-Host ($Prefix + $text)
        $count++
        if ($count -ge $Limit) { break }
    }
    return $count
}

function Get-WindowBlocks {
    param([string[]] $Lines)

    $blocks = New-Object System.Collections.Generic.List[object]
    $currentHeader = $null
    $currentLines = New-Object System.Collections.Generic.List[string]

    foreach ($line in $Lines) {
        if ($line -match '^\s*Window #\d+') {
            if ($null -ne $currentHeader) {
                $blocks.Add([pscustomobject]@{ Header = $currentHeader; Lines = @($currentLines) }) | Out-Null
            }
            $currentHeader = $line.Trim()
            $currentLines = New-Object System.Collections.Generic.List[string]
            continue
        }
        if ($null -ne $currentHeader) {
            $currentLines.Add($line) | Out-Null
        }
    }

    if ($null -ne $currentHeader) {
        $blocks.Add([pscustomobject]@{ Header = $currentHeader; Lines = @($currentLines) }) | Out-Null
    }

    return @($blocks)
}

function Print-Focus {
    param(
        [string[]] $WindowLines,
        [string[]] $ActivitiesLines
    )

    Section 'FOCUS / FOREGROUND'

    $currentFocus = First-LineMatch $WindowLines 'mCurrentFocus='
    $focusedApp = First-LineMatch $WindowLines 'mFocusedApp='
    $resumedActivity = First-LineMatch $ActivitiesLines 'mResumedActivity:|mResumedActivity='
    $topResumed = First-LineMatch $ActivitiesLines 'topResumedActivity=|mTopResumedActivity='

    if ($currentFocus) { Write-Host "  Current focus window : $currentFocus" } else { Write-Host '  Current focus window : not found' }
    if ($focusedApp) { Write-Host "  Focused app          : $focusedApp" } else { Write-Host '  Focused app          : not found' }
    if ($resumedActivity) { Write-Host "  Resumed activity     : $resumedActivity" }
    if ($topResumed) { Write-Host "  Top resumed activity : $topResumed" }

    Write-Host ''
    Write-Host '  Extra focus hints:'
    $count = Print-Matches $WindowLines 'mCurrentFocus=|mFocusedApp=|mInputMethodTarget=|mTopFocusedDisplayId=|mFocusedWindow=' 20 '    - ' -Unique
    if ($count -eq 0) { Write-Host '    - No extra focus hints found' }
}

function Print-VisibleWindows {
    param([string[]] $WindowLines)

    Section 'VISIBLE / DRAWN WINDOWS'

    $visiblePattern = 'mViewVisibility=0x0|ViewVisibility=0x0|isReadyForDisplay=true|mHasSurface=true|hasSurface=true|mDrawState=HAS_DRAWN|mPolicyVisibility=true|mPolicyVisibilityAfterAnim=true|mVisible=true|shown=true'
    $removedPattern = 'mViewVisibility=0x8|mDestroying=true|mRemoved=true|mAnimatingExit=true|mWindowRemovalAllowed=true'

    $blocks = Get-WindowBlocks $WindowLines
    $count = 0
    foreach ($block in $blocks) {
        $joined = ($block.Lines -join "`n")
        $isVisible = $joined -match $visiblePattern
        $isRemoved = $joined -match $removedPattern
        if (-not $isVisible -or $isRemoved) { continue }

        Write-Host "  - $($block.Header)"

        $pkgLine = First-LineMatch $block.Lines '(package=|mAttrs=|ActivityRecord\{|Window\{)'
        if ($pkgLine) { Write-Host "    package/activity: $pkgLine" }

        $typeLine = First-LineMatch $block.Lines '(ty=|type=|mAttrs=)'
        if ($typeLine -and $typeLine -ne $pkgLine) { Write-Host "    attrs/type      : $typeLine" }

        $count++
        if ($count -ge $LimitWindows) { break }
    }

    if ($count -eq 0) {
        Write-Host '  No visible windows found by heuristic. Raw fallback:'
        $fallback = Print-Matches $WindowLines '^\s*Window #\d+' $LimitWindows '  - ' -Unique
        if ($fallback -eq 0) { Write-Host '  - No Window lines found' }
    }
}

function Print-Tasks {
    param([string[]] $ActivitiesLines)

    Section 'TASKS / BACK STACK'

    $pattern = '^\s*(\* )?(RootTask|Task|TaskRecord|Stack)\{|^\s*Task id #|^\s*\* Task\{|^\s*RootTask #\d+|^\s*Stack #\d+'
    $count = Print-Matches $ActivitiesLines $pattern $LimitTasks '  - ' -Unique
    if ($count -eq 0) {
        Write-Host '  No task lines found. Check raw activities.txt for Android-version-specific format.'
    }

    Write-Host ''
    Write-Host '  Resumed / top activities:'
    $topCount = Print-Matches $ActivitiesLines 'mResumedActivity|topResumedActivity|Hist #\d+: ActivityRecord' 30 '    - ' -Unique
    if ($topCount -eq 0) { Write-Host '    - No resumed/top activity lines found' }
}

function Print-Services {
    param([string[]] $ActivityLines)

    Section 'RUNNING / ACTIVE SERVICES'

    $pattern = 'ServiceRecord\{|^\s*\* ServiceRecord|^\s*Active services|^\s*User \d+ active services|^\s*Running services'
    $count = Print-Matches $ActivityLines $pattern $LimitServices '  - ' -Unique
    if ($count -eq 0) {
        Write-Host '  No ServiceRecord lines found. This can happen on newer builds or restricted dumps.'
    }
}

function Print-ProcessMemoryState {
    param([string[]] $ActivityLines)

    Section 'PROCESS MEMORY STATE / OOM ADJ'

    $inProc = $false
    $procCount = 0
    $nextDetails = 0

    foreach ($line in $ActivityLines) {
        if ($line -match 'Process LRU list|ACTIVITY MANAGER RUNNING PROCESSES|Oom Adjustments') {
            $inProc = $true
        }

        if ($inProc -and ($line -match 'Proc #\d+:|ProcessRecord\{')) {
            $procCount++
            if ($procCount -le $LimitProcesses) {
                Write-Host ('  - ' + (($line -replace '\s+', ' ').Trim()))
                $nextDetails = 4
            }
            continue
        }

        if ($inProc -and $nextDetails -gt 0 -and ($line -match 'oom:|state:|lastPss=|lastCachedPss=|adj=|setAdj=|curAdj=|curRaw=|setRaw=|cached=')) {
            if ($procCount -le $LimitProcesses) {
                Write-Host ('      ' + (($line -replace '\s+', ' ').Trim()))
            }
            $nextDetails--
            continue
        }

        if ($inProc -and $procCount -gt 0 -and ($line -match '^ACTIVITY MANAGER [A-Z ]+$')) {
            break
        }
    }

    if ($procCount -eq 0) {
        Write-Host '  No process memory/OOM lines found by parser. Raw hints:'
        $count = Print-Matches $ActivityLines 'Process LRU list|Proc #\d+:|oom:|state:|lastPss=' 120 '  - ' -Unique
        if ($count -eq 0) { Write-Host '  - No memory state hints found' }
    }
}

function Invoke-Dump {
    param(
        [hashtable] $CommandMap,
        [string] $Key,
        [string] $OutputFile,
        [string] $WorkDir,
        [string[]] $AdbBaseArgs
    )

    $cmd = $CommandMap[$Key]
    if ([string]::IsNullOrWhiteSpace($cmd)) { throw "Missing command for key '$Key'" }

    Write-Host "[collect] adb $($AdbBaseArgs -join ' ') shell $cmd"
    $parts = $cmd -split '\s+'
    $outPath = Join-Path $WorkDir $OutputFile
    $errPath = "$outPath.err"

    & adb @AdbBaseArgs shell @parts > $outPath 2> $errPath

    if ($LASTEXITCODE -ne 0) {
        Write-Host "WARN: failed to run: adb shell $cmd" -ForegroundColor Yellow
    }
}

try {
    if (-not (Get-Command adb -ErrorAction SilentlyContinue)) {
        throw 'adb not found. Add Android SDK platform-tools to PATH.'
    }

    $commands = Read-CommandsFile -Path $CommandsFile

    $adbBaseArgs = @()
    if ($DeviceSerial) { $adbBaseArgs += @('-s', $DeviceSerial) }

    & adb @adbBaseArgs get-state *> $null
    if ($LASTEXITCODE -ne 0) {
        throw "adb device is not ready. Run 'adb devices'. If there are many devices, use: aaos_dump_report.bat -s <serial>"
    }

    if ($RawDir) {
        $WorkDir = [System.IO.Path]::GetFullPath($RawDir)
        New-Item -ItemType Directory -Path $WorkDir -Force | Out-Null
        $removeRaw = $false
    } else {
        $stamp = Get-Date -Format 'yyyyMMdd-HHmmss'
        $WorkDir = Join-Path $env:TEMP "aaos-dump-report-$stamp-$([Guid]::NewGuid().ToString('N').Substring(0, 6))"
        New-Item -ItemType Directory -Path $WorkDir -Force | Out-Null
        $removeRaw = -not $KeepRaw
    }

    Invoke-Dump $commands 'activity' 'activity.txt' $WorkDir $adbBaseArgs
    Invoke-Dump $commands 'activities' 'activities.txt' $WorkDir $adbBaseArgs
    Invoke-Dump $commands 'window' 'window.txt' $WorkDir $adbBaseArgs

    $activityFile = Join-Path $WorkDir 'activity.txt'
    $activitiesFile = Join-Path $WorkDir 'activities.txt'
    $windowFile = Join-Path $WorkDir 'window.txt'

    $activityLines = Get-Content -LiteralPath $activityFile -ErrorAction SilentlyContinue
    $activitiesLines = Get-Content -LiteralPath $activitiesFile -ErrorAction SilentlyContinue
    $windowLines = Get-Content -LiteralPath $windowFile -ErrorAction SilentlyContinue

    Write-Host ''
    Write-Host 'Android Dumpsys Short Report'
    Write-Host ('Generated at : ' + (Get-Date -Format 'yyyy-MM-dd HH:mm:ss zzz'))
    if ($DeviceSerial) { Write-Host "ADB target   : $DeviceSerial" } else { Write-Host 'ADB target   : default device' }
    Write-Host "Raw dir      : $WorkDir"

    Print-Focus $windowLines $activitiesLines
    Print-VisibleWindows $windowLines
    Print-Tasks $activitiesLines
    Print-Services $activityLines
    Print-ProcessMemoryState $activityLines

    if ($KeepRaw -or $RawDir) {
        Write-Host ''
        Write-Host "Raw dumps saved in: $WorkDir"
        Write-Host '  - activity.txt'
        Write-Host '  - activities.txt'
        Write-Host '  - window.txt'
    }

    if ($removeRaw) {
        Remove-Item -LiteralPath $WorkDir -Recurse -Force -ErrorAction SilentlyContinue
    }

    exit 0
}
catch {
    Write-Host ''
    Write-Host ('ERROR: ' + $_.Exception.Message) -ForegroundColor Red
    Write-Host ''
    Write-Host "Hints:"
    Write-Host "  - Check adb: adb devices"
    Write-Host "  - If many devices are connected: aaos_dump_report.bat -s emulator-5554"
    Write-Host "  - Make sure Android SDK platform-tools is added to PATH"
    exit 1
}
